import numpy as np

class CRBExperiment:
    """
    Verify Cramér-Rao bound through estimation experiments.
    """

    def __init__(self, distribution='gaussian'):
        self.distribution = distribution

    def fisher_information(self, params):
        """Compute Fisher information for single observation."""
        if self.distribution == 'gaussian':
            sigma = params['sigma']
            return 1 / sigma**2  # For mean estimation
        elif self.distribution == 'bernoulli':
            p = params['p']
            return 1 / (p * (1 - p))
        elif self.distribution == 'poisson':
            lam = params['lambda']
            return 1 / lam

    def theoretical_bound(self, true_params, n_samples):
        """
        Compute Cramér-Rao lower bound for n i.i.d. samples.
        """
        I = self.fisher_information(true_params)
        return 1 / (n_samples * I)

    def sample(self, params, n_samples):
        """Generate samples from distribution."""
        if self.distribution == 'gaussian':
            return np.random.normal(params['mu'], params['sigma'], n_samples)
        elif self.distribution == 'bernoulli':
            return np.random.binomial(1, params['p'], n_samples)
        elif self.distribution == 'poisson':
            return np.random.poisson(params['lambda'], n_samples)

    def mle_estimator(self, samples):
        """
        Compute MLE for the parameter.
        """
        if self.distribution == 'gaussian':
            return np.mean(samples)  # MLE for mean
        elif self.distribution == 'bernoulli':
            return np.mean(samples)  # MLE for p
        elif self.distribution == 'poisson':
            return np.mean(samples)  # MLE for lambda

    def run_simulation(self, true_params, n_samples, n_trials=1000):
        """
        Run multiple estimation trials.
        """
        estimates = []

        for _ in range(n_trials):
            samples = self.sample(true_params, n_samples)
            estimate = self.mle_estimator(samples)
            estimates.append(estimate)

        estimates = np.array(estimates)

        empirical_var = np.var(estimates)
        cr_bound = self.theoretical_bound(true_params, n_samples)
        efficiency = cr_bound / empirical_var if empirical_var > 0 else 0

        return {
            'empirical_variance': empirical_var,
            'cramer_rao_bound': cr_bound,
            'efficiency': efficiency,
            'mean_estimate': np.mean(estimates),
            'true_value': list(true_params.values())[0]
        }

    def efficiency_vs_sample_size(self, true_params, sample_sizes, n_trials=1000):
        """
        Study how efficiency changes with sample size.
        """
        results = []

        for n in sample_sizes:
            res = self.run_simulation(true_params, n, n_trials)
            results.append({
                'n': n,
                'variance': res['empirical_variance'],
                'bound': res['cramer_rao_bound'],
                'efficiency': res['efficiency']
            })

        return results

# Test Gaussian
print("Gaussian Mean Estimation")
print("="*60)
exp = CRBExperiment('gaussian')
true_params = {'mu': 5.0, 'sigma': 2.0}

for n in [10, 50, 100, 500]:
    results = exp.run_simulation(true_params, n, n_trials=2000)
    print(f"n={n:4d}: Var={results['empirical_variance']:.6f}, "
          f"CR={results['cramer_rao_bound']:.6f}, "
          f"Eff={results['efficiency']:.4f}")

# Test Bernoulli
print("\nBernoulli Estimation")
print("="*60)
exp_bern = CRBExperiment('bernoulli')

for p in [0.2, 0.5, 0.8]:
    results = exp_bern.run_simulation({'p': p}, n_samples=100, n_trials=2000)
    print(f"p={p}: Var={results['empirical_variance']:.6f}, "
          f"CR={results['cramer_rao_bound']:.6f}, "
          f"Eff={results['efficiency']:.4f}")
